import java.util.HashMap;
import java.util.Objects;
import java.util.Stack;

public class RobotReturnToOrigin {
    public static boolean betterJudgeCircle(String moves) {
        int x = 0,y = 0;

        for(int i=0;i<moves.length();i++){
            if(moves.charAt(i) == 'U') x++;
            else if(moves.charAt(i) == 'D') x--;
            else if(moves.charAt(i) == 'L') y++;
            else y--;
        }

        if(x != 0 || y != 0) return false;

        return true;
    }
    public static boolean judgeCircle(String moves){
        HashMap<Character, Integer> map = new HashMap<>();
        map.put('U', 0);
        map.put('D', 0);
        map.put('L', 0);
        map.put('R', 0);

        for(int i=0;i<moves.length();i++){
            map.put(moves.charAt(i),map.get(moves.charAt(i))+1);
        }

        if(map.get('U').equals(map.get('D')) && map.get('L').equals(map.get('R'))){
            return true;
        }

        return false;
    }

    public static void main(String[] args){
        String moves = "";
        System.out.println(judgeCircle(moves));
    }
}
